uint16_t lookup_floor(float phase) {
  return lookup_value[((uint16_t)(phase * PHASE_TO_INDEX)) & LOOKUP_MASK];
}

uint16_t lookup_nearest(float phase) {
  return lookup_value[((uint16_t)(phase * PHASE_TO_INDEX + 0.5)) & LOOKUP_MASK];
}

uint16_t lookup_interpolate(float phase) {
  float fraction = phase * PHASE_TO_INDEX;
  uint16_t index = fraction;
  fraction -= index;
  if (fraction == 0.0) {
    return lookup_value[index & LOOKUP_MASK];
  } else {
    return lookup_value[index & LOOKUP_MASK] + fraction * ((float)lookup_value[(index + 1) & LOOKUP_MASK] - (float)lookup_value[index & LOOKUP_MASK]);
  }
}
